"use strict";(self.webpackChunkblogv2_dev=self.webpackChunkblogv2_dev||[]).push([[6911],{8523:(e,n,a)=>{a.r(n),a.d(n,{data:()=>s});const s={key:"v-45a29610",path:"/blogs/Cloud&Server/kernel.html",title:"Linux Kernel Build：Linux 内核编译",lang:"zh-CN",frontmatter:{title:"Linux Kernel Build：Linux 内核编译",Date:"2018-6-8",tag:["Linux"],category:["Server","Linux"],summary:"1. 预备工作 阿里云开源镜像站下载内核：阿里云。下载内核和patch包。 安装必要的软件 把内核目录linux-4.x.x和补丁patch都复制到/usr/src，然后进入/usr/src 2. 准备编译 选择load→OK→Save→OK→EXIT→EXIT的执行顺序。 3. 开始编译 4. 更新grub --- 内核与内核模块 内核模块 一般内核模块放",head:[["meta",{property:"og:url",content:"https://vueblog.weigao.cc/blogs/Cloud&Server/kernel.html"}],["meta",{property:"og:site_name",content:"WW"}],["meta",{property:"og:title",content:"Linux Kernel Build：Linux 内核编译"}],["meta",{property:"og:type",content:"article"}],["meta",{property:"og:updated_time",content:"2022-04-17T08:12:32.000Z"}],["meta",{property:"og:locale",content:"zh-CN"}],["meta",{property:"article:tag",content:"Linux"}],["meta",{property:"article:modified_time",content:"2022-04-17T08:12:32.000Z"}]]},excerpt:"",headers:[{level:2,title:"1. 预备工作",slug:"_1-预备工作",children:[]},{level:2,title:"2. 准备编译",slug:"_2-准备编译",children:[]},{level:2,title:"3. 开始编译",slug:"_3-开始编译",children:[]},{level:2,title:"4. 更新grub",slug:"_4-更新grub",children:[]},{level:2,title:"内核与内核模块",slug:"内核与内核模块",children:[{level:3,title:"内核模块",slug:"内核模块",children:[]},{level:3,title:"内核模块的查看",slug:"内核模块的查看",children:[]},{level:3,title:"内核模块的加载与删除",slug:"内核模块的加载与删除",children:[]}]}],git:{createdTime:1644237761e3,updatedTime:1650183152e3,contributors:[{name:"chenweigao",email:"297859260@qq.com",commits:2},{name:"chenweigao",email:"chenweigao1@huawei.com",commits:1}]},readingTime:{minutes:2.02,words:606},filePathRelative:"blogs/Cloud&Server/kernel.md"}},4831:(e,n,a)=>{a.r(n),a.d(n,{default:()=>u});var s=a(6252);const i=(0,s._)("h2",{id:"_1-预备工作",tabindex:"-1"},[(0,s._)("a",{class:"header-anchor",href:"#_1-预备工作","aria-hidden":"true"},"#"),(0,s.Uk)(" 1. 预备工作")],-1),l=(0,s.Uk)("阿里云开源镜像站下载内核："),d={href:"http://mirrors.aliyun.com/",target:"_blank",rel:"noopener noreferrer"},c=(0,s.Uk)("阿里云"),r=(0,s.Uk)("。下载内核和patch包。"),t=(0,s.uE)('<p>安装必要的软件</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment">#安装必要的软件</span>\n<span class="token function">apt-get</span> <span class="token function">install</span> kernel-package build-essential libncurses5-dev fakeroot\n<span class="token comment">#解压缩内核</span>\n<span class="token function">tar</span> -xzf linux-4.x.x.tar.gz\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>把内核目录linux-4.x.x和补丁patch都复制到/usr/src，然后进入/usr/src</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">cp</span> linux-x.x /usr/src -rf\n<span class="token function">cp</span> patch-x.x /user/src\n<span class="token builtin class-name">cd</span> /usr/src\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_2-准备编译" tabindex="-1"><a class="header-anchor" href="#_2-准备编译" aria-hidden="true">#</a> 2. 准备编译</h2><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment">#复制当前内核的config文件到linux-x.x/下</span>\n<span class="token function">cp</span> linux-headers-<span class="token variable"><span class="token variable">$(</span><span class="token function">uname</span> -r<span class="token variable">)</span></span>/.config linux-x.x/\n<span class="token builtin class-name">cd</span> linux-x.x/\n<span class="token function">make</span> menuconfig\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>选择load→OK→Save→OK→EXIT→EXIT的执行顺序。</p><h2 id="_3-开始编译" tabindex="-1"><a class="header-anchor" href="#_3-开始编译" aria-hidden="true">#</a> 3. 开始编译</h2><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment"># 编译启动映像，N表示CPU核数，单核为2.双核为4，以此类推</span>\n<span class="token function">make</span> bzImage -jN\n<span class="token comment">#编译模块</span>\n<span class="token function">make</span> modules -jN\n<span class="token comment">#安装模块</span>\n<span class="token function">make</span> modules-install\n<span class="token comment">#安装内核</span>\n<span class="token function">make</span> <span class="token function">install</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_4-更新grub" tabindex="-1"><a class="header-anchor" href="#_4-更新grub" aria-hidden="true">#</a> 4. 更新grub</h2><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment"># 4.5.0为版本号</span>\nmkinitramfs <span class="token number">4.5</span>.0 -o /boot/initrd.img-4.5.0\nupdate-grub2\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="内核与内核模块" tabindex="-1"><a class="header-anchor" href="#内核与内核模块" aria-hidden="true">#</a> 内核与内核模块</h2><h3 id="内核模块" tabindex="-1"><a class="header-anchor" href="#内核模块" aria-hidden="true">#</a> 内核模块</h3><p>一般内核模块放置在<code>lib/modules/$(uname -r)/kernel</code>当中，包括arch, drivers和net等子文件。</p><p>在新建模块的时候，会遇到模块的依赖性问题，在 <code>lib/modules/$(uname -r/modules.dep)</code> 文件中存储，这个文件的创建使用 <code>depmod [-Ane]</code> 命令：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>depmod <span class="token punctuation">[</span>-Ane<span class="token punctuation">]</span>\n-A: 查找到新模块再更新该文件\n-n: 不写入modules, 但在屏幕上输出\n-e: 显示出当前已加载但不可执行的模块名称\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>举例：如果我做好了一个网卡驱动程序，文件名为a.ko，则更新内核模块：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">cp</span> a.ko /lib/modules/<span class="token variable"><span class="token variable">$(</span><span class="token function">uname</span> -r <span class="token variable">)</span></span>/kernel/drivers/net\ndepmod\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="内核模块的查看" tabindex="-1"><a class="header-anchor" href="#内核模块的查看" aria-hidden="true">#</a> 内核模块的查看</h3><p><code>lsmod</code>命令可查看已加载的模块，查看内核模块的信息，使用<code>modinfo</code></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>modinfo <span class="token punctuation">[</span>-adln<span class="token punctuation">]</span> <span class="token punctuation">[</span>module_name<span class="token operator">|</span>filename<span class="token punctuation">]</span>\n-a: 仅列出作者名称\n-d: 仅description\n-l: 仅列出授权\n-n: 列出该模块的详细路径\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>e.g. 列出ath模块的路径：<code>modinfo -n ath</code></p><h3 id="内核模块的加载与删除" tabindex="-1"><a class="header-anchor" href="#内核模块的加载与删除" aria-hidden="true">#</a> 内核模块的加载与删除</h3><p><code>modprobe</code>命令可解决依赖性并决定需要加载的模块，优于<code>insmod</code></p><p>对于删除模块：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>rmmmod <span class="token punctuation">[</span>-fw<span class="token punctuation">]</span> module_name\n-f: 强势删除，无论是否被使用\n-w: 若该模块在使用，则等待该模块使用完后再删除\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>但是通常情况下，不推荐使用<code>insmod</code>和<code>rmmod</code>命令，万一模块存在依赖属性的问题时，将无法直接加载或删除该模块，所以使用<code>modprobe</code>来处理加载模块的问题：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>modprobe <span class="token punctuation">[</span>-lcfr<span class="token punctuation">]</span> module_name\n-r: 删除某个模块\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div>',29),o={},u=(0,a(3744).Z)(o,[["render",function(e,n){const a=(0,s.up)("ExternalLinkIcon");return(0,s.wg)(),(0,s.iD)("div",null,[(0,s.kq)("more"),i,(0,s._)("p",null,[l,(0,s._)("a",d,[c,(0,s.Wm)(a)]),r]),t])}]])},3744:(e,n)=>{n.Z=(e,n)=>{const a=e.__vccOpts||e;for(const[e,s]of n)a[e]=s;return a}}}]);